.darma-loader-darma-custom-164 {
  color: var(--loader-color, #0f766e);
width: 45px;
aspect-ratio: 1;
--c: linear-gradient(135deg,currentColor,var(--loader-secondary-color, #2dd4bf));
--m: radial-gradient(farthest-side,currentColor 92%,#0000);
background:
var(--c),var(--m),
var(--c),var(--m),
var(--c),var(--m);
background-size: 8px 15px,8px 8px;
background-repeat: no-repeat;
animation: darma-loader-darma-custom-164-l14 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-164-l14 {
0%,
10% {background-position: 0 0 ,0 100%,50% 0 ,50% 100%,100% 0 ,100% 100%}
33% {background-position: 0 100%,0 0 ,50% 0 ,50% 100%,100% 0 ,100% 100%}
66% {background-position: 0 100%,0 0 ,50% 100%,50% 0 ,100% 0 ,100% 100%}
90%,
100%{background-position: 0 100%,0 0 ,50% 100%,50% 0 ,100% 100%,100% 0 }
}

